**정리**: 사용자가 클릭/Space로 on/off를 토글하는 접근성 토글 스위치예요. props는 `checked: boolean`, `onChange: (next: boolean) => void`, `label: string`.

```tsx
import { useCallback, type KeyboardEvent } from 'react';

export interface ToggleProps {
  checked: boolean;
  onChange: (next: boolean) => void;
  label: string;
  disabled?: boolean;
}

export function Toggle({ checked, onChange, label, disabled }: ToggleProps) {
  const handleToggle = useCallback(() => {
    if (!disabled) onChange(!checked);
  }, [checked, disabled, onChange]);

  const handleKey = useCallback(
    (e: KeyboardEvent<HTMLButtonElement>) => {
      if (e.key === ' ' || e.key === 'Enter') {
        e.preventDefault();
        handleToggle();
      }
    },
    [handleToggle],
  );

  return (
    <button
      type="button"
      role="switch"
      aria-checked={checked}
      aria-label={label}
      aria-disabled={disabled || undefined}
      onClick={handleToggle}
      onKeyDown={handleKey}
      className={`toggle ${checked ? 'is-on' : ''} ${disabled ? 'is-disabled' : ''}`}
    >
      <span className="toggle-thumb" />
      <span className="toggle-text">{label}</span>
    </button>
  );
}
```

**사용 예시**
```tsx
const [on, setOn] = useState(false);
<Toggle checked={on} onChange={setOn} label="알림 받기" />
```

**테스트**
```tsx
import { render, screen, fireEvent } from '@testing-library/react';
import { Toggle } from './Toggle';

test('Space로 토글된다', () => {
  const onChange = vi.fn();
  render(<Toggle checked={false} onChange={onChange} label="알림" />);
  const sw = screen.getByRole('switch');
  fireEvent.keyDown(sw, { key: ' ' });
  expect(onChange).toHaveBeenCalledWith(true);
});
```
